class HierarchicalMemory:
    def __init__(self, short_term_capacity: int, promotion_threshold: int = 3):
        self.st_capacity = short_term_capacity
        self.promotion_threshold = promotion_threshold
        self._short_term = []  # list of memory dicts, FIFO
        self._long_term = {}   # id -> memory dict

    def add(self, memory: dict):
        mem = dict(memory)
        mem['access_count'] = mem.get('access_count', 0)
        mem['tier'] = 'short'
        if len(self._short_term) >= self.st_capacity:
            evicted = self._short_term.pop(0)
            evicted['tier'] = 'long'
            self._long_term[evicted['id']] = evicted
        self._short_term.append(mem)

    def access(self, memory_id: str):
        # Check short-term first
        for i, m in enumerate(self._short_term):
            if m['id'] == memory_id:
                m['access_count'] += 1
                if m['access_count'] >= self.promotion_threshold:
                    promoted = self._short_term.pop(i)
                    promoted['tier'] = 'long'
                    self._long_term[memory_id] = promoted
                return
        # Check long-term
        if memory_id in self._long_term:
            self._long_term[memory_id]['access_count'] += 1

    def retrieve(self, query: str, top_k: int) -> list:
        query_words = set(query.lower().split())
        results = []
        for m in self._short_term:
            score = sum(1 for w in query_words if w in m['content'].lower())
            results.append((m, float(score)))
        for m in self._long_term.values():
            score = sum(1 for w in query_words if w in m['content'].lower()) * 0.8
            results.append((m, float(score)))
        results.sort(key=lambda x: -x[1])
        return results[:top_k]

    def status(self) -> dict:
        return {
            'short_term_count': len(self._short_term),
            'long_term_count': len(self._long_term)
        }
